prompt --application/pages/page_00040
begin
wwv_flow_imp_page.create_page(
 p_id=>40
,p_name=>'AI Document Designer'
,p_alias=>'AI-DOCUMENT-DESIGNER'
,p_step_title=>'AI Document Designer'
,p_warn_on_unsaved_changes=>'N'
,p_autocomplete_on_off=>'OFF'
,p_javascript_file_urls=>wwv_flow_string.join(wwv_flow_t_varchar2(
'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js',
'https://cdnjs.cloudflare.com/ajax/libs/jspdf/3.0.3/jspdf.umd.min.js'))
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'(function () {',
'    const generateButton = document.querySelector("#GENERATE_AI_DOCUMENT");',
'    const pdfButton = document.querySelector("#DOWNLOAD_PDF");',
'',
'    const box = document.querySelector("#aiDocProgressBox");',
'    const bar = document.querySelector("#aiDocProgressBar");',
'    const percent = document.querySelector("#aiDocProgressPercent");',
'    const title = document.querySelector("#aiDocProgressTitle");',
'    const message = document.querySelector("#aiDocProgressMessage");',
'    const preview = document.querySelector("#aiDocPreview");',
'',
'    let pulseTimer = null;',
'',
'    function setProgress(value, titleText, messageText, busy) {',
'        if (box) {',
'            box.style.display = "block";',
'            box.classList.toggle("is-busy", Boolean(busy));',
'            box.classList.toggle("is-indeterminate", value === null);',
'        }',
'',
'        if (bar) {',
'            if (value === null) {',
'                bar.style.width = "35%";',
'            } else {',
'                const safeValue = Math.max(0, Math.min(100, Number(value || 0)));',
'                bar.style.width = safeValue + "%";',
'            }',
'        }',
'',
'        if (percent) {',
'            if (value === null) {',
'                percent.textContent = "";',
'                percent.style.display = "none";',
'            } else {',
'                const safeValue = Math.max(0, Math.min(100, Number(value || 0)));',
'                percent.textContent = safeValue + "%";',
'                percent.style.display = "";',
'            }',
'        }',
'',
'        if (title) {',
'            title.textContent = titleText || "";',
'        }',
'',
'        if (message) {',
'            message.textContent = messageText || "";',
'        }',
'    }',
'',
'    function setButtonBusy(isBusy) {',
'        if (!generateButton) {',
'            return;',
'        }',
'',
'        generateButton.disabled = isBusy;',
'        generateButton.textContent = isBusy ? "Generating..." : "Generate AI Document";',
'    }',
'',
'    function stopPulse() {',
'        if (pulseTimer) {',
'            window.clearInterval(pulseTimer);',
'            pulseTimer = null;',
'        }',
'    }',
'',
'    function startAiPulse() {',
'        let dots = 0;',
'',
'        stopPulse();',
'',
'        pulseTimer = window.setInterval(function () {',
'            dots = (dots + 1) % 4;',
'',
'            if (message) {',
'                message.textContent = "AI is designing the report" + ".".repeat(dots);',
'            }',
'        }, 600);',
'    }',
'',
'    function getItemValue(itemName) {',
'        const item = apex.item(itemName);',
'',
'        if (!item) {',
'            return "";',
'        }',
'',
'        return item.getValue() || "";',
'    }',
'',
'    function getDefaultModel(provider) {',
'        if (provider === "GROQ") {',
'            return "openai/gpt-oss-120b";',
'        }',
'',
'        if (provider === "OPENAI") {',
'            return "gpt-4.1";',
'        }',
'',
'        if (provider === "ANTHROPIC") {',
'            return "claude-sonnet-4-5";',
'        }',
'',
'        if (provider === "GOOGLE") {',
'            return "gemini-2.5-flash";',
'        }',
'',
'        return "";',
'    }',
'',
'    function validateAiSettings() {',
'        const provider = getItemValue("P40_AI_PROVIDER").trim().toUpperCase();',
'        let model = getItemValue("P40_AI_MODEL").trim();',
'        const apiKey = getItemValue("P40_AI_API_KEY").trim();',
'',
'        const allowedProviders = ["GROQ", "OPENAI", "ANTHROPIC", "GOOGLE"];',
'',
'        if (!provider || !allowedProviders.includes(provider)) {',
'            return {',
'                valid: false,',
'                message: "Provider must be GROQ, OPENAI, ANTHROPIC, or GOOGLE."',
'            };',
'        }',
'',
'        if (!model) {',
'            model = getDefaultModel(provider);',
'        }',
'',
'        if (!model) {',
'            return {',
'                valid: false,',
'                message: "Model is required."',
'            };',
'        }',
'',
'        if (!apiKey) {',
'            return {',
'                valid: false,',
'                message: "API key is required."',
'            };',
'        }',
'',
'        return {',
'            valid: true,',
'            provider: provider,',
'            model: model,',
'            apiKey: apiKey',
'        };',
'    }',
'',
'    function generateReport() {',
'        const aiSettings = validateAiSettings();',
'',
'        if (!aiSettings.valid) {',
'            setProgress(100, "Failed", aiSettings.message, false);',
'            setButtonBusy(false);',
'            return;',
'        }',
'',
'        if (preview) {',
'            preview.innerHTML = "";',
'        }',
'',
'        setButtonBusy(true);',
'        setProgress(10, "Starting", "Preparing request...", false);',
'',
'        apex.server.process(',
'            "AI_DOC_PRECHECK",',
'            {',
'                pageItems: "#P40_SQL_QUERY,#P40_QUESTION,#P40_MAX_ROWS"',
'            },',
'            {',
'                dataType: "text",',
'                success: function (responseText) {',
'                    let data;',
'',
'                    try {',
'                        data = JSON.parse(responseText || "{}");',
'                    } catch (error) {',
'                        setProgress(',
'                            100,',
'                            "Failed",',
'                            "AI_DOC_PRECHECK did not return valid JSON. Response: " + (responseText || "[empty response]"),',
'                            false',
'                        );',
'                        setButtonBusy(false);',
'                        return;',
'                    }',
'',
'                    if (!data || data.success !== true) {',
'                        setProgress(',
'                            100,',
'                            "Failed",',
'                            data && data.error ? data.error : "SQL precheck failed.",',
'                            false',
'                        );',
'                        setButtonBusy(false);',
'                        return;',
'                    }',
'',
'                    setProgress(25, "SQL validated", "Metadata and sample rows are ready.", false);',
'',
'                    setTimeout(function () {',
'                        setProgress(null, "AI designing", "AI is designing the report...", true);',
'                        startAiPulse();',
'',
'                        apex.server.process(',
'                            "AI_DOC_GENERATE_HTML",',
'                            {',
'                                pageItems: "#P40_SQL_QUERY,#P40_QUESTION,#P40_MAX_ROWS",',
'                                x01: aiSettings.provider,',
'                                x02: aiSettings.model,',
'                                x03: aiSettings.apiKey',
'                            },',
'                            {',
'                                dataType: "text",',
'                                success: function (html) {',
'                                    stopPulse();',
'',
'                                    if (!html || html.trim().length === 0) {',
'                                        setProgress(100, "Failed", "AI returned empty HTML.", false);',
'                                        setButtonBusy(false);',
'                                        return;',
'                                    }',
'',
'                                    if (preview) {',
'                                        preview.innerHTML = html;',
'                                    }',
'',
'                                    setProgress(100, "Completed", "Report is ready.", false);',
'                                    setButtonBusy(false);',
'                                },',
'                                error: function (jqXHR, textStatus, errorThrown) {',
'                                    stopPulse();',
'',
'                                    const errorText =',
'                                        jqXHR && jqXHR.responseText',
'                                            ? jqXHR.responseText',
'                                            : errorThrown || textStatus || "AI generation failed.";',
'',
'                                    setProgress(100, "Failed", errorText, false);',
'                                    setButtonBusy(false);',
'                                }',
'                            }',
'                        );',
'                    }, 250);',
'                },',
'                error: function (jqXHR, textStatus, errorThrown) {',
'                    const errorText =',
'                        jqXHR && jqXHR.responseText',
'                            ? jqXHR.responseText',
'                            : errorThrown || textStatus || "SQL precheck failed.";',
'',
'                    setProgress(100, "Failed", errorText, false);',
'                    setButtonBusy(false);',
'                }',
'            }',
'        );',
'    }',
'',
'    async function downloadPdf() {',
'        const report = document.querySelector("#ai-doc-report");',
'',
'        if (!report) {',
'            apex.message.alert("Generate the report first.");',
'            return;',
'        }',
'',
'        if (!window.html2canvas || !window.jspdf || !window.jspdf.jsPDF) {',
'            apex.message.alert("PDF libraries are not loaded.");',
'            return;',
'        }',
'',
'        const originalText = pdfButton ? pdfButton.innerText : "";',
'',
'        function sanitizeGradientsForCanvas(root) {',
'            const allElements = [root].concat(Array.from(root.querySelectorAll("*")));',
'',
'            allElements.forEach(function (el) {',
'                const style = window.getComputedStyle(el);',
'',
'                const backgroundImage = style.backgroundImage || "";',
'                const borderImageSource = style.borderImageSource || "";',
'                const maskImage = style.maskImage || "";',
'                const webkitMaskImage = style.webkitMaskImage || "";',
'',
'                if (',
'                    backgroundImage.includes("gradient(") ||',
'                    backgroundImage.includes("linear-gradient") ||',
'                    backgroundImage.includes("radial-gradient") ||',
'                    backgroundImage.includes("conic-gradient")',
'                ) {',
'                    const backgroundColor = style.backgroundColor;',
'',
'                    el.style.backgroundImage = "none";',
'',
'                    if (',
'                        backgroundColor &&',
'                        backgroundColor !== "rgba(0, 0, 0, 0)" &&',
'                        backgroundColor !== "transparent"',
'                    ) {',
'                        el.style.backgroundColor = backgroundColor;',
'                    } else {',
'                        el.style.backgroundColor = "#ffffff";',
'                    }',
'                }',
'',
'                if (',
'                    borderImageSource.includes("gradient(") ||',
'                    borderImageSource.includes("linear-gradient") ||',
'                    borderImageSource.includes("radial-gradient") ||',
'                    borderImageSource.includes("conic-gradient")',
'                ) {',
'                    el.style.borderImage = "none";',
'                    el.style.borderImageSource = "none";',
'                }',
'',
'                if (',
'                    maskImage.includes("gradient(") ||',
'                    webkitMaskImage.includes("gradient(")',
'                ) {',
'                    el.style.maskImage = "none";',
'                    el.style.webkitMaskImage = "none";',
'                }',
'',
'                const colorProperties = [',
'                    "color",',
'                    "backgroundColor",',
'                    "borderColor",',
'                    "borderTopColor",',
'                    "borderRightColor",',
'                    "borderBottomColor",',
'                    "borderLeftColor",',
'                    "outlineColor",',
'                    "textDecorationColor"',
'                ];',
'',
'                colorProperties.forEach(function (propertyName) {',
'                    const value = style[propertyName];',
'',
'                    if (',
'                        value &&',
'                        (',
'                            value.includes("oklch(") ||',
'                            value.includes("lab(") ||',
'                            value.includes("lch(") ||',
'                            value.includes("color-mix(")',
'                        )',
'                    ) {',
'                        if (propertyName === "color") {',
'                            el.style.color = "#111827";',
'                        } else if (propertyName === "backgroundColor") {',
'                            el.style.backgroundColor = "#ffffff";',
'                        } else {',
'                            el.style[propertyName] = "#e5e7eb";',
'                        }',
'                    }',
'                });',
'            });',
'        }',
'',
'        try {',
'            if (pdfButton) {',
'                pdfButton.disabled = true;',
'                pdfButton.innerText = "Generating PDF...";',
'            }',
'',
'            if (document.fonts && document.fonts.ready) {',
'                await document.fonts.ready;',
'            }',
'',
'            await new Promise(function (resolve) {',
'                setTimeout(resolve, 300);',
'            });',
'',
'            const wrapper = document.createElement("div");',
'            wrapper.style.position = "fixed";',
'            wrapper.style.left = "-100000px";',
'            wrapper.style.top = "0";',
'            wrapper.style.width = report.scrollWidth + "px";',
'            wrapper.style.background = "#ffffff";',
'            wrapper.style.zIndex = "-1";',
'            wrapper.style.pointerEvents = "none";',
'            wrapper.style.overflow = "visible";',
'',
'            const clonedReport = report.cloneNode(true);',
'            clonedReport.style.width = report.scrollWidth + "px";',
'            clonedReport.style.maxWidth = "none";',
'            clonedReport.style.backgroundColor = "#ffffff";',
'            clonedReport.style.transform = "none";',
'',
'            wrapper.appendChild(clonedReport);',
'            document.body.appendChild(wrapper);',
'',
'            sanitizeGradientsForCanvas(clonedReport);',
'',
'            const canvas = await html2canvas(clonedReport, {',
'                scale: 2,',
'                useCORS: false,',
'                allowTaint: false,',
'                backgroundColor: "#ffffff",',
'                logging: false,',
'                imageTimeout: 0,',
'                windowWidth: clonedReport.scrollWidth,',
'                windowHeight: clonedReport.scrollHeight,',
'                scrollX: 0,',
'                scrollY: 0',
'            });',
'',
'            if (wrapper.parentNode) {',
'                document.body.removeChild(wrapper);',
'            }',
'',
'            if (!canvas || canvas.width === 0 || canvas.height === 0) {',
'                throw new Error("html2canvas returned an empty canvas.");',
'            }',
'',
'            const pdf = new window.jspdf.jsPDF({',
'                orientation: "portrait",',
'                unit: "pt",',
'                format: "a4",',
'                compress: true',
'            });',
'',
'            const pageWidth = pdf.internal.pageSize.getWidth();',
'            const pageHeight = pdf.internal.pageSize.getHeight();',
'',
'            const imgScale = pageWidth / canvas.width;',
'            const pdfPageHeightInCanvasPixels = Math.floor(pageHeight / imgScale);',
'',
'            let sourceY = 0;',
'            let firstPage = true;',
'',
'            while (sourceY < canvas.height) {',
'                const sliceHeight = Math.min(',
'                    pdfPageHeightInCanvasPixels,',
'                    canvas.height - sourceY',
'                );',
'',
'                const pageCanvas = document.createElement("canvas");',
'                pageCanvas.width = canvas.width;',
'                pageCanvas.height = sliceHeight;',
'',
'                const ctx = pageCanvas.getContext("2d");',
'',
'                if (!ctx) {',
'                    throw new Error("Could not create canvas rendering context.");',
'                }',
'',
'                ctx.fillStyle = "#ffffff";',
'                ctx.fillRect(0, 0, pageCanvas.width, pageCanvas.height);',
'',
'                ctx.drawImage(',
'                    canvas,',
'                    0,',
'                    sourceY,',
'                    canvas.width,',
'                    sliceHeight,',
'                    0,',
'                    0,',
'                    canvas.width,',
'                    sliceHeight',
'                );',
'',
'                const imgData = pageCanvas.toDataURL("image/jpeg", 0.95);',
'                const slicePdfHeight = sliceHeight * imgScale;',
'',
'                if (!firstPage) {',
'                    pdf.addPage();',
'                }',
'',
'                pdf.addImage(',
'                    imgData,',
'                    "JPEG",',
'                    0,',
'                    0,',
'                    pageWidth,',
'                    slicePdfHeight,',
'                    undefined,',
'                    "FAST"',
'                );',
'',
'                firstPage = false;',
'                sourceY += sliceHeight;',
'            }',
'',
'            pdf.save("ai-designed-report.pdf");',
'        } catch (error) {',
'            console.error("PDF generation failed:", error);',
'',
'            apex.message.alert(',
'                "PDF generation failed:\n\n" +',
'                (error && error.message ? error.message : String(error))',
'            );',
'        } finally {',
'            const tempWrappers = document.querySelectorAll("div[style*=''-100000px'']");',
'',
'            tempWrappers.forEach(function (el) {',
'                if (el && el.parentNode) {',
'                    el.parentNode.removeChild(el);',
'                }',
'            });',
'',
'            if (pdfButton) {',
'                pdfButton.disabled = false;',
'                pdfButton.innerText = originalText || "Download PDF";',
'            }',
'        }',
'    }',
'',
'    if (generateButton) {',
'        generateButton.addEventListener("click", function (event) {',
'            event.preventDefault();',
'            generateReport();',
'        });',
'    }',
'',
'    if (pdfButton) {',
'        pdfButton.addEventListener("click", function (event) {',
'            event.preventDefault();',
'            downloadPdf();',
'        });',
'    }',
'})();'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'#aiDocProgressBox.is-indeterminate #aiDocProgressBar {',
'    width: 35%;',
'    animation: aiDocIndeterminate 1.2s ease-in-out infinite;',
'}',
