wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(133399637404788325333)
,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'AI_DOC_PRECHECK'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    l_metadata clob;',
'    l_sample   clob;',
'    l_json     clob;',
'',
'    procedure print_clob(',
'        p_clob in clob',
'    ) is',
'        l_pos   number := 1;',
'        l_len   number;',
'        l_chunk varchar2(32767);',
'    begin',
'        if p_clob is null then',
'            return;',
'        end if;',
'',
'        l_len := dbms_lob.getlength(p_clob);',
'',
'        while l_pos <= l_len loop',
'            l_chunk := dbms_lob.substr(p_clob, 32767, l_pos);',
'            htp.prn(l_chunk);',
'            l_pos := l_pos + 32767;',
'        end loop;',
'    end;',
'begin',
'    l_metadata := ai_doc_designer_pkg.describe_query_json(',
'        p_sql => :P40_SQL_QUERY',
'    );',
'',
'    l_sample := ai_doc_designer_pkg.query_data_json(',
'        p_sql      => :P40_SQL_QUERY,',
'        p_max_rows => 5',
'    );',
'',
'    apex_json.initialize_clob_output;',
'    apex_json.open_object;',
'    apex_json.write(''success'', true);',
'    apex_json.write(''message'', ''SQL validated and sample data prepared.'');',
'    apex_json.close_object;',
'',
'    l_json := apex_json.get_clob_output;',
'    apex_json.free_output;',
'',
'    print_clob(l_json);',
'exception',
'    when others then',
'        apex_json.initialize_clob_output;',
'        apex_json.open_object;',
'        apex_json.write(''success'', false);',
'        apex_json.write(''error'', sqlerrm);',
'        apex_json.close_object;',
'',
'        l_json := apex_json.get_clob_output;',
'        apex_json.free_output;',
'',
'        print_clob(l_json);',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>133399637404788325333
);
